solution_code:
#include <iostream>
#include <iomanip>

int main() {
    int a, b;
    std::cin >> a >> b;

    int intResult = a / b;
    std::cout << "Integer division: " << intResult << "\n";

    double da = a;  // implicit int -> double conversion
    double dblResult = da / b;
    std::cout << "Double division: " << std::fixed << std::setprecision(1) << dblResult << "\n";

    return 0;
}

